const email = $input.first().json;

// ═══════════════════════════════════════════════════════════════
// 🏠 PLATEFORMES IMMO RECONNUES — Ajouter/retirer selon besoins
// ═══════════════════════════════════════════════════════════════
const PLATFORM_DOMAINS = [
  // Portails nationaux
  'seloger.com',
  'leboncoin.fr',
  'bienici.com',
  'logic-immo.com',
  'pap.fr',
  'superimmo.com',
  'ouestfrance-immo.com',
  'lefigaroimmobilier.com',
  'meilleurs-agents.com',
  // Réseaux d'agences
  'century21.fr',
  'orpi.com',
  'laforet.com',
  'guy-hoquet.com',
  'era-immobilier.fr',
  'stéphaneplaza.com',
  // Autres
  'bellesdemeures.com',
  'proprietes-de-france.com',
  'fnaim.fr',
];

// Mots-clés dans l'objet email (filet de sécurité si le domaine est inconnu)
const SUBJECT_KEYWORDS = [
  'demande de contact',
  'nouveau contact',
  'demande de visite',
  'vous a envoyé un message',
  'contact pour votre annonce',
  'nouvelle demande',
  'intéressé par votre bien',
  'a consulté votre annonce',
  'a pris contact',
];
// ═══════════════════════════════════════════════════════════════

const fromAddr = (
  email.from?.value?.[0]?.address ||
  email.from?.text || ''
).toLowerCase();

const subject = (email.subject || '').toLowerCase();

const domainMatch  = PLATFORM_DOMAINS.some(d => fromAddr.includes(d));
const subjectMatch = SUBJECT_KEYWORDS.some(kw => subject.includes(kw));

if (!domainMatch && !subjectMatch) {
  // Email ignoré — pas une plateforme immo reconnue
  return [];
}

// Identifier la plateforme source pour le dashboard
let source = 'email';
if (fromAddr.includes('seloger.com'))           source = 'seloger';
else if (fromAddr.includes('leboncoin.fr'))      source = 'leboncoin';
else if (fromAddr.includes('bienici.com'))       source = 'bienici';
else if (fromAddr.includes('logic-immo.com'))    source = 'logic-immo';
else if (fromAddr.includes('pap.fr'))            source = 'pap';
else if (fromAddr.includes('ouestfrance-immo'))  source = 'ouestfrance-immo';
else if (fromAddr.includes('century21'))         source = 'century21';
else if (fromAddr.includes('orpi'))              source = 'orpi';

// Passer l'email enrichi au nœud suivant
return [{ json: { ...email, _source: source } }];

// ═══════════════════════════════════════════════════════
// ⚙️  CONFIGURATION — Remplir cette valeur avant utilisation
// ═══════════════════════════════════════════════════════
const N8N_WEBHOOK_BASE = 'https://REMPLACER.n8n.cloud';
// ═══════════════════════════════════════════════════════

const email = $input.first().json;

const fromName  = email.from?.value?.[0]?.name  || '';
const fromEmail = email.from?.value?.[0]?.address || email.from?.text || '';

// Tenter d'extraire prénom/nom depuis le nom de l'expéditeur
const parts  = fromName.trim().split(/\s+/);
const prenom = parts[0]  || '';
const nom    = parts.slice(1).join(' ') || '';

const body = email.text
  || (email.html || '').replace(/<[^>]+>/g, ' ').replace(/\s{2,}/g, ' ').trim();

const msgId = (email.messageId || '').replace(/[<>]/g, '') || String(Date.now());

return [{
  json: {
    id:      'imap_' + msgId,
    prenom,
    nom,
    email:   fromEmail,
    tel:     '',
    bien:    '',
    ville:   '',
    source:  email._source || 'email',
    projet:  email.subject || '',
    message: body.substring(0, 3000),
    _webhookUrl: N8N_WEBHOOK_BASE + '/webhook/leadflow-traitement'
  }
}];
